import numpy as np

def relu(x):
    return np.maximum(0, x)

def batch_norm(x, gamma, beta, eps=1e-5):
    mean = x.mean(axis=(0, 2, 3), keepdims=True)
    var = x.var(axis=(0, 2, 3), keepdims=True)
    x_norm = (x - mean) / np.sqrt(var + eps)
    return gamma.reshape(1,-1,1,1) * x_norm + beta.reshape(1,-1,1,1)

def conv_nd(x, W, b, stride=1, padding=0):
    N, C_in, H, W_in = x.shape
    C_out, _, kH, kW = W.shape
    if padding > 0:
        x = np.pad(x, ((0,0),(0,0),(padding,padding),(padding,padding)))
    H_out = (x.shape[2] - kH) // stride + 1
    W_out = (x.shape[3] - kW) // stride + 1
    out = np.zeros((N, C_out, H_out, W_out))
    for n in range(N):
        for co in range(C_out):
            for i in range(H_out):
                for j in range(W_out):
                    patch = x[n,:,i*stride:i*stride+kH,j*stride:j*stride+kW]
                    out[n,co,i,j] = np.sum(patch * W[co]) + b[co]
    return out

def bottleneck_block(x, params, stride=1):
    shortcut = x
    # 1x1 reduce
    out = conv_nd(x, params['W1'], params['b1'], stride=1, padding=0)
    out = batch_norm(out, params['gamma1'], params['beta1'])
    out = relu(out)
    # 3x3 conv (with stride)
    out = conv_nd(out, params['W2'], params['b2'], stride=stride, padding=1)
    out = batch_norm(out, params['gamma2'], params['beta2'])
    out = relu(out)
    # 1x1 expand
    out = conv_nd(out, params['W3'], params['b3'], stride=1, padding=0)
    out = batch_norm(out, params['gamma3'], params['beta3'])
    # Projection shortcut
    if 'W_proj' in params and params['W_proj'] is not None:
        shortcut = conv_nd(shortcut, params['W_proj'], params['b_proj'], stride=stride, padding=0)
    return relu(out + shortcut)
